### Define Custom Field Hook Type (PayloadCMS, TypeScript)

Source: https://github.com/payloadcms/payload/blob/main/docs/hooks/fields.mdx

This snippet shows how to define a custom TypeScript type for PayloadCMS field hooks using the `FieldHook` generic. It illustrates the arguments passed to a field hook, including `value`, `data`, `siblingData`, `originalDoc`, `operation`, and `req`, and emphasizes type safety for the hook's return value.

```ts
import type { FieldHook } from 'payload'

// Field hook type is a generic that takes three arguments:
// 1: The document type
// 2: The value type
// 3: The sibling data type

type ExampleFieldHook = FieldHook<ExampleDocumentType, string, SiblingDataType>

const exampleFieldHook: ExampleFieldHook = (args) => {
  const {
    value, // Typed as `string` as shown above
    data, // Typed as a Partial of your ExampleDocumentType
    siblingData, // Typed as a Partial of SiblingDataType
    originalDoc, // Typed as ExampleDocumentType
    operation,
    req,
  } = args

  // Do something here...

  return value // should return a string as typed above, undefined, or null
}
```

