### Define Blocks Field in Payload CMS

Source: https://github.com/payloadcms/payload/blob/main/tools/claude-plugin/skills/payload/reference/FIELDS.md

Defines a 'blocks' field type in Payload CMS, allowing for a collection of different block structures. It utilizes TypeScript for type safety and imports necessary types from 'payload'. The 'blocks' field can contain various predefined Block types, such as 'HeroBlock' and 'ContentBlock'.

```typescript
import type { BlocksField, Block } from 'payload'

const HeroBlock: Block = {
  slug: 'hero',
  interfaceName: 'HeroBlock',
  fields: [
    {
      name: 'heading',
      type: 'text',
      required: true,
    },
    {
      name: 'background',
      type: 'upload',
      relationTo: 'media',
    },
  ],
}

const ContentBlock: Block = {
  slug: 'content',
  fields: [
    {
      name: 'text',
      type: 'richText',
    },
  ],
}

const blocksField: BlocksField = {
  name: 'layout',
  type: 'blocks',
  blocks: [HeroBlock, ContentBlock],
}
```

